-- ============================================================
-- PLATAFORMA LIVIU — Migración 17: plantilla real de rutina
-- "Mesociclo 2" de Liviu, importada desde su Excel de entreno.
--  · 12 semanas (microciclos), 6 sesiones/semana con sus ejercicios
--    y 3 series prescritas cada uno (reps, RIR/técnica, carga).
--  · Se guarda como PLANTILLA (es_plantilla = true, sin cliente),
--    para poder asignarla luego a cualquier cliente desde
--    "Plantillas" y ajustarla si hace falta.
-- ============================================================

do $$
declare
  v_datos jsonb := '{"nombre_rutina":"Mesociclo 2 (LIVIU) — plantilla","semanas":[{"semana":1,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":170,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":"GOMA AZUL","rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":300,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":150,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":37.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":120,"carga_texto":"H","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":210,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":200,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":45,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":2,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":170,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":"GOMA AZUL","rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":300,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":150,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":37.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":120,"carga_texto":"H","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":210,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":200,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":45,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":3,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":190,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":170,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":"GOMA AZUL","rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":75,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":300,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":155,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":37.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":120,"carga_texto":"H","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":200,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":125,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":82.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":45,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":20,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":82.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":62.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":4,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":140,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":165,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":310,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":160,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":32.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":125,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":82.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":82.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":5,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":65,"carga_texto":"P","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":315,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":160,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":32.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":27.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":"-","rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":82.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":6,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":110,"carga_texto":"HACK","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":140,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":160,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":310,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":290,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":160,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":37.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":27.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":27.5,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":37.5,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":76.25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":7,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":"G 💚","rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":315,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":275,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":165,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":27.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":87.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":37.5,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":"🟢","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":"🟢","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":60,"carga_texto":"🟢","rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":"cuerda","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":"cuerda","rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":8,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":75,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":310,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":270,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":165,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":105,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":250,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":75,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":37.5,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":9,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":320,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":280,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":170,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":150,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":42.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":50,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":250,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":240,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":75,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":37.5,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":10,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":330,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":290,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":180,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":250,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":230,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":75,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":37.5,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":40,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":11,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":340,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":280,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":"sentado","rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":180,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":42.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":55,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":22.5,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":12.5,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":260,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":70,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":35,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":70,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]},{"semana":12,"dias":[{"orden":0,"nombre":"PUSH","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas y cadera extendidas","notas":"-Realízalo de pie en: máquina o Multipower\n-No adelantes la cadera al subir\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Coloca los talones debajo de la barra\n-Añade un escalón/step debajo de las punteras para buscar el máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":120,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca inclinado 45º en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":110,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null}]},{"orden":4,"ejercicio":"Sentadilla Hack en Multipower","notas":"-Lleva la espalda perpendicular al suelo en todo el ROM\n-Lleva la cadera debajo de la barra en todo el ROM\n-Coloca los pies lo más atrás posible para aumentar la fuerzas reactivas de fricción sobre estos (coloca si es necesario un pequeño tacón)\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Press plano en máquina de placas","notas":"-Empuja con los codos detrás de las manos\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps (brazos al torso), si la máquina converge, mejor\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no bajes los codos al final\n-Al final extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Press unilateral en prensa 45º con banda de resistencia","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":320,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":280,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":1,"nombre":"PULL","ejercicios":[{"orden":1,"ejercicio":"Aducciones de cadera sentado en máquina","notas":"-Mantén la espalda baja y la cadera apoyadas en todo el ROM (90º de flexión de cadera)\n-Ánclate a la máquina lo máximo posible a través de los agarres y el respaldo\n-No apliques fuerzas intencionales con los pies, si puedes apoya los talones, no las plantas de los pies","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":95,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":85,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Peso muerto piernas rígidas con barra libre","notas":"-Atrasa la cadera lo máximo posible a medida que bajas manteniéndola arriba del todo\n-Utiliza la mínima flexión de rodillas posible\n-Corta la bajada en el momento que no seas capaz de seguir atrasando la cadera sin flexionar las rodillas\n-Lleva el cuello en línea con la espalda\n-Mantén la espalda neutra\n-Lleva la barra pegada a ti y no la apoyes en el suelo","series":[{"reps":5,"reps_max":8,"kg":180,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":140,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral en máquina de palancas","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":42.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo con mancuernas contra banco inclinado 30º","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":35,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Remo-jalón unilateral","notas":"-Tracciona llevando el antebrazo en línea con el cable\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Remo en máquina de palancas (Dorian) con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":120,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Pull over desde polea alta con agarre neutro (énfasis acortamiento)","notas":"-Mantén los codos bloqueados en una semi-extensión\n-Dibuja un semi-círculo por delante del cuerpo hasta llevar el húmero a la altura del torso\n-Mantén una retroversión pélvica y flexión activa de la columna\n-Colócate alejado de la polea\n-Inclínate hacia delante ligeramente\n-Mantén el hombro y la escápula descendidos y no subas de los 120º de flexión de hombro","series":[{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":60,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":2,"nombre":"UPPER PUSH + ARMS","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro en máquina (pec deck)","notas":"-Utiliza un agarre neutro inverso (palmas de las manos hacia fuera) o prono\n-Apoya las manos contra la palanca vertical y aplica fuerza contra ella\n-Lleva las manos por debajo de los hombros (60º de abd de hombro)\n-Mantén una protracción escapular, no juntes las escápulas en ningún momento\n-No pases de los hombros con las manos","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press de banca inclinado 45º con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en acercar los bíceps (brazos al torso)\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que bajas y no atrases los codos abajo\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":35,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Flexiones de codos desde polea baja con agarre supino","notas":"-Extiende por completo los codos al final de cada repetición\n-No te balancees","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":65,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Extensiones de codo unilaterales desde polea alta","notas":"-Utiliza muñequera y agárrala\n-No te coloques de lado totalemente a la polea, sino en diagonal\n-Baja el cable pegado al cuerpo, por el otro lado de la cabeza\n-Lleva el húmero (brazo) en línea con el cable y extiende hacia fuera del cuerpo\n-No relajes el tríceps al apoyar el bíceps sobre el antebrazo (al comienzo)","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Elevaciones laterales de pie entre poleas bajas (cerca entre sí)","notas":"-Codos extendidos por completo\n-No te inclines ni te dejes caer\n-Lo más cerca posible a las poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Lleva los cables por delante del cuerpo\n-Haz coincidir los cable perpendiculares a los brazos al final del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n- Lleva el cable por delante del cuerpo","series":[{"reps":5,"reps_max":8,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":null,"tecnica":"F"},{"reps":0,"reps_max":null,"kg":10,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Curl bayesian sentado en banco entre poleas bajas","notas":"-Extiende por completo los codos al comienzo de cada rep\n-Lleva los húmeros (brazos) paralelos a los cables en todo momento\n-Aléjate bastante de las poleas (1,5m aprox)\n-No adelantes los codos al final del ROM (mantenlos atrás)\n-Intenta que las poleas no estén muy separadas entre sí, que no vengan en diagonal\n-Átate con straps en caso de que el agarre sea limitante","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Press francés en banco inclinado 45º con mancuernas","notas":"-Lleva los codos ligeramente separados (hacia fuera)\n-Mantén los húmeros (brazos) lo más perpendiculares al suelo y paralelos entre sí en todo el ROM\n-No relajes los tríceps al contactar los bíceps con los antebrazos, al comienzo\n-No modifiques la posición de los codos al subir\n-Agarra las mancuernas por el límite","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":12.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":3,"nombre":"LEGS","ejercicios":[{"orden":1,"ejercicio":"Flexiones plantares con rodillas extendidas y cadera flexionada","notas":"-Realízalo sentad@ en: máquina o prensa (cualquier tipo)\n-NMantén una anteversión pélvica y extensión del cuello durante todo el ROM para evitar carga neural\n-No flexiones las rodillas (ni un poco) en ningún momento\n-Máximo ROM\n-Apoya hasta el metatarso del pie (no más)","series":[{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":10,"reps_max":14,"kg":null,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":2,"ejercicio":"Flexiones de rodillas tumbado en máquina de placas","notas":"-No hagas excesiva anteversión pélvica\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Aplica fuerza con la rodillas contra el punto de restricción frontal\n-Extiende por completo la rodilla abajo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Extensiones de cadera en máquina","notas":"-Coloca los pies con el ancho de las caderas y que estén debajo de las rodillas cuando estés arriba\n-Orienta las punteras de los pies ligeramente hacia fuera\n-Controla el empuje desde abajo para no llegar arriba con inercia","series":[{"reps":5,"reps_max":8,"kg":260,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":220,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Press unilateral en prensa 45º","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca el respaldo lo más perpendicular posible a la plataforma de los pies que tu movilidad de tobillo te permita\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla al final\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar al final, inspiración-espiración-inspiración al bajar y empuja en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":8,"reps_max":10,"kg":130,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Sentadilla en Hack pendular","notas":"-Coloca el pie lo más abajo posible en la plataforma sin que se llegue a levantar el talón\n-Empuja con la rodilla en la dirección de la puntera del pie (que no se meta hacia dentro)\n-Coloca los hombros en el punto de intersección del respaldo con el apoyo vertical y apoya la cabeza\n-No separes la espalda baja cuando llegues al final del ROM (abajo)\n-Extiende con control la rodilla arriba\n-Estandariza el n.º de respiraciones en cada repetición (2: espiración al llegar arriba, inspiración-espiración-inspiración al bajar y sube en apnea)\n-Máxima profundidad a no ser que se indique lo contrario","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":5,"reps_max":8,"kg":75,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de rodillas sentado en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos con flexión dorsal (\"punteras hacia las tibias\")\n-Ánclate si es posible a los agarres y al respaldo\n-En caso de que tu máquina tenga el punto de restricción anterior, por encima de las rodillas, acércalo a estas lo máximo posible","series":[{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":70,"carga_texto":null,"rir":null,"tecnica":"P"}]},{"orden":7,"ejercicio":"Extensiones de rodillas en máquina de placas","notas":"-No separes la espalda baja y la cadera del asiento y el respaldo\n-Alinea el eje de la máquina con tus ejes anatómicos (rodillas)\n-Lleva los tobillos neutros (\"punteras hacia arriba\")\n-Ánclate si es posible a los agarres y al respaldo","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":8,"ejercicio":"Sentadillas búlgaras en Multipower","notas":"-Coloca el pie ejecutante lo más atrás posible sin que se llegue a levantar el talón (puedes usar un pequeño tacón)\n-Lleva la rodilla de la pierna atrasada, por detrás de la cadera\n-Lleva la espalda y la cadera debajo de la barra, perpendiculares al suelo\n-Realiza todo el ROM con el tronco erguido\n-Lleva el apoyo de atrás a la altura de las rodillas\n-Coloca un step debajo del pie ejecutante en caso de que puedas aprovechar la profundidad por la movilidad de cadera","series":[{"reps":5,"reps_max":8,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":4,"nombre":"UPPER PUSH","ejercicios":[{"orden":1,"ejercicio":"Press de banca plano con mancuernas","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":5,"reps_max":8,"kg":50,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":40,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Press inclinado 45º entre poleas bajas","notas":"-Empuja con los antebrazos en línea con los cables\n-Aplica fuerza hacia delante con los pies antes de la fase concéntrica\n-Piensa en acercar los bíceps al torso, no las manos entre sí\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que llegues al final y no bajes los codos abajo\n-Al final extiende por completo los codos, espira y comienza a bajar\n-Lleva siempre los cables por fuera de los codos pero pegados a estos","series":[{"reps":5,"reps_max":8,"kg":55,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":45,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":35,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Press de banca plano en Multipower con banda de resistencia inversa","notas":"-Empuja con los antebrazos perpendiculares al suelo\n-Piensa en juntar tus manos y acercar los bíceps\n-No realices excesivo arco lumbar ni separes la cadera del banco\n-Mantén una retracción escapular durante todo el ROM\n-Lleva tus hombros entre los 30-60º de abducción vertical\n-Decelera a medida que baja la barra y no llegues a tocar el torso\n-Arriba extiende por completo los codos, espira y comienza a bajar","series":[{"reps":6,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":70,"carga_texto":null,"rir":null,"tecnica":"P+ISO HOLD"}]},{"orden":4,"ejercicio":"Elevaciones laterales tumbado entre poleas en posición de estiramiento","notas":"-Codos extendidos por completo\n-Túmbate en un banco inclinado entre 30-45º\n-Cuando extiendes los brazos, las manos deberían cruzar la línea entre poleas\n-Usa muñequeras y agarra anillas para mayor irradiación\n-Haz coincidir los cable perpendiculares a los brazos al comienzo del ROM\n-Piensa en llevar las manos lejos de ti, no hacia arriba\n-Eleva los hombros lo menos posible arriba\n-Si las poleas son cercanas, realiza las elevas por delante del cuerpo, sino, por los lados en el plano escapular","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":15,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Extensiones de codos en máquina de palancas (agarre estrecho) (fondos)","notas":"-Intenta anclarte a la máquina para que no te levante\n-No te inclines demasiado\n-Termina con los hombros en línea con las manos y la perpendicular con el suelo\n-No separes mucho los brazos del tronco","series":[{"reps":5,"reps_max":8,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":null,"carga_texto":"-","rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Extensiones de codo unilaterales trasnuca desde polea baja","notas":"-No es necesario que coloques la polea abajo del todo\n-Alinea el húmero (brazo) al cable\n-Utiliza una muñequera y agárrala\n-Agárrate con la mano libre si es posible\n-Colócate de lado a la polea (a no ser que se indique lo contrario)","series":[{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]},{"orden":5,"nombre":"UPPER PULL","ejercicios":[{"orden":1,"ejercicio":"Abducciones de hombro horizontales unilaterales desde polea a media altura","notas":"-Utiliza muñequera y mete el brazo (hasta la mitad del antebrazo)\n-Lleva una rotación externa de hombro (aplica fuerza con el exterior del antebrazo)\n-Agarra un maneral externo para mayor irradiación\n-Lleva una trayectoria descendente sacando el cable desde el lateral del cuerpo a la altura de la vista\n-No pases de la línea del hombro con la mano (no retraigas la escápula al final)\n-Mantén entorno a los 60º de abd de hombro","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":20,"carga_texto":null,"rir":null,"tecnica":"P"},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":2,"ejercicio":"Remo en máquina de placas agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)","series":[{"reps":5,"reps_max":8,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":100,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":3,"ejercicio":"Remo unilateral en máquina de palancas (Dorian) con agarre neutro","notas":"-Tracciona llevando el antebrazo en línea con la mano\n-Consúltame para saber cómo colocarte respecto a la carga y modificar el perfil de resistencia\n-Mantén una retroversión pélvica y una flexión de la columna\n-No anteriorices el hombro atrás\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula delante\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":90,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":70,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":4,"ejercicio":"Jalón unilateral desde polea alta","notas":"-Tracciona llevando el antebrazo perpendicular al suelo y en línea con la mano\n-No anteriorices el hombro abajo\n-No vayas de delante a atrás con el tronco\n-No descuelgues el hombro ni la escápula arriba\n-Mantén una retroversión pélvica y una flexión de la columna\n-Acerca el brazo al torso por delante del cuerpo con el codos en dirección a la cadera\n-Agárrate con la mano libre\n-No pases de la línea del tronco con los codos","series":[{"reps":5,"reps_max":8,"kg":40,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":5,"ejercicio":"Remo T con agarre prono y amplio","notas":"-Dale a tus escápulas la máxima movilidad (retracción y protracción)\n-\"Descuelga los hombros\" al comienzo y \"saca el pecho\" al final\n-Pasa de la línea del tronco con los codos\n-Tracciona con los codos detrás de las manos\n-No anteriorices los hombros atrás\n-No vayas de delante a atrás con el tronco\n-Utiliza el agarre que te permita llevar los hombros entre 30-60º de abducción (separados del tronco)\n-Apoya los pies a la altura de la cadera (usa steps si es necesario)","series":[{"reps":5,"reps_max":8,"kg":80,"carga_texto":null,"rir":0,"tecnica":null},{"reps":8,"reps_max":10,"kg":60,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":6,"ejercicio":"Flexiones de codos en banco Scott con barra Z","notas":"-Extiende los codos por completo abajo en cada rep\n-No separes los codos del respaldo en ningún momento\n-Apoya el brazo entero sobre el respaldo (sin incluir la axila)\n-Lleva un agarre ligeramente más estrecho que el biacromial\n-Átate en caso de limitar el agarre","series":[{"reps":6,"reps_max":10,"kg":30,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":25,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]},{"orden":7,"ejercicio":"Curl martillo con mancuernas de pie tumbado contra el banco scott del revés","notas":"-Extiende por completo los codos abajo en cada rep\n-No flexiones ni extiendas los hombros arriba (no separes los codos del tronco)\n-Agarra las mancuernas por el límite\n-Usa straps en caso de que limite el agarre","series":[{"reps":6,"reps_max":10,"kg":17.5,"carga_texto":null,"rir":0,"tecnica":null},{"reps":6,"reps_max":10,"kg":15,"carga_texto":null,"rir":0,"tecnica":null},{"reps":0,"reps_max":null,"kg":null,"carga_texto":null,"rir":null,"tecnica":null}]}]}]}]}'::jsonb;
  v_rutina uuid;
  v_semana jsonb;
  v_dia jsonb;
  v_ej jsonb;
  v_dia_id uuid;
  v_rutejercicio_id uuid;
  v_ejercicio_id uuid;
begin
  insert into public.rutinas (nombre, es_plantilla, activa, semana_actual)
  values (v_datos->>'nombre_rutina', true, true, 1)
  returning id into v_rutina;

  for v_semana in select * from jsonb_array_elements(v_datos->'semanas')
  loop
    for v_dia in select * from jsonb_array_elements(v_semana->'dias')
    loop
      insert into public.rutina_dias (rutina_id, orden, nombre, semana)
      values (v_rutina, (v_dia->>'orden')::int, v_dia->>'nombre', (v_semana->>'semana')::int)
      returning id into v_dia_id;

      for v_ej in select * from jsonb_array_elements(v_dia->'ejercicios')
      loop
        select id into v_ejercicio_id from public.ejercicios
        where nombre = v_ej->>'ejercicio' and creado_por is null
        limit 1;

        if v_ejercicio_id is null then
          raise exception 'Ejercicio no encontrado en la biblioteca: %', v_ej->>'ejercicio';
        end if;

        insert into public.rutina_ejercicios (dia_id, ejercicio_id, orden, descanso_seg, notas)
        values (v_dia_id, v_ejercicio_id, (v_ej->>'orden')::int, 120, v_ej->>'notas')
        returning id into v_rutejercicio_id;

        insert into public.series_prescritas
          (rutina_ejercicio_id, orden, tipo, reps, reps_max, kg, carga_texto, rir, tecnica)
        select
          v_rutejercicio_id, (ord - 1)::int, 'efectiva',
          (s->>'reps')::int, (s->>'reps_max')::int, (s->>'kg')::numeric,
          s->>'carga_texto', (s->>'rir')::int, s->>'tecnica'
        from jsonb_array_elements(v_ej->'series') with ordinality as t(s, ord);
      end loop;
    end loop;
  end loop;

  raise notice 'Plantilla creada con id %', v_rutina;
end $$;
